#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while(T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        int a0, d;
        int min_a0 = A[0];
        int min_d = A[1] - A[0];
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                a0 = A[i];
                d = A[j] - A[i];
                int changes = 0;
                for (int k = 0; k < N; k++) {
                    if (A[k] != a0 + k * d) {
                        changes++;
                    }
                }
                if (changes <= K) {
                    if (a0 < min_a0 || (a0 == min_a0 && d < min_d)) {
                        min_a0 = a0;
                        min_d = d;
                    }
                }
            }
        }
        for (int i = 0; i < N; i++) {
            printf("%d ", min_a0 + i * min_d);
        }
        printf("\n");
    }
    return 0;
}

