import sys
T = int(sys.stdin.readline())
for _ in range(T):
    N, K = map(int, sys.stdin.readline().split())
    A = list(map(int, sys.stdin.readline().split()))
    a0, d = A[0], A[1] - A[0]
    min_a0, min_d = a0, d
    for i in range(N):
        for j in range(i + 1, N):
            a0, d = A[i], A[j] - A[i]
            changes = sum(1 for k in range(N) if A[k] != a0 + k * d)
            if changes <= K:
                if a0 < min_a0 or (a0 == min_a0 and d < min_d):
                    min_a0, min_d = a0, d
    print(' '.join(map(str, [min_a0 + i * min_d for i in range(N)])))

